const fs = require('fs/promises');
const crypto = require('crypto');

app.get('/report', async (req, res, next) => {
  try {
    // Async read: the thread serves other requests while the OS/pool reads.
    const data = await fs.readFile('/big/report.csv', 'utf8');
    res.send(process(data));
  } catch (err) { next(err); }
});

app.get('/hash', (req, res, next) => {
  // Async crypto uses the libuv thread pool, off the main thread.
  crypto.pbkdf2(req.body.pw, salt, 1_000_000, 64, 'sha512', (err, hash) => {
    if (err) return next(err);
    res.send(hash.toString('hex'));
  });
});

