const { pipeline } = require('stream/promises');
const fs = require('fs');
const zlib = require('zlib');

// Streams the file through gzip to disk with automatic backpressure:
// each stage pauses when the next is slow, so memory stays bounded.
// pipeline also propagates errors and destroys all streams on failure.
await pipeline(
  fs.createReadStream('/big/10gb.log'),
  zlib.createGzip(),
  fs.createWriteStream('/out/10gb.log.gz')
);
// Memory stays at a few buffer-sized chunks regardless of file size.

