const fs = require('fs');
const readline = require('readline');
const { pipeline } = require('stream/promises');
const { Transform } = require('stream');

async function redactNdjson(inputPath, outputPath) {
  // Readable source: streams the file in chunks, never loading it all.
  const input = fs.createReadStream(inputPath, { encoding: 'utf8' });

  // Transform: parse each NDJSON line, redact, re-serialize.
  // (For line splitting at scale, a split transform or readline is used;
  //  here we build a Transform that buffers partial lines safely.)
  let buffer = '';
  const redact = new Transform({
    readableObjectMode: false,
    writableObjectMode: false,
    transform(chunk, _enc, cb) {
      buffer += chunk;
      const lines = buffer.split('\n');
      buffer = lines.pop();              // keep the trailing partial line
      try {
        for (const line of lines) {
          if (!line) continue;
          const rec = JSON.parse(line);
          delete rec.ssn;                // redact a sensitive field
          this.push(JSON.stringify(rec) + '\n');
        }
        cb();
      } catch (err) {
        cb(err);                         // propagate parse errors
      }
    },
    flush(cb) {                          // handle the last line, no newline
      try {
        if (buffer.trim()) {
          const rec = JSON.parse(buffer);
          delete rec.ssn;
          this.push(JSON.stringify(rec) + '\n');
        }
        cb();
      } catch (err) { cb(err); }
    },
  });

  const output = fs.createWriteStream(outputPath);

  // pipeline wires the stages, enforces backpressure, propagates errors,
  // and destroys every stream if any stage fails.
  await pipeline(input, redact, output);
}

// Usage:
// await redactNdjson('/data/events.ndjson', '/data/events.redacted.ndjson');

// hash-worker.js  (runs on a separate thread)
const { workerData, parentPort } = require('worker_threads');
const crypto = require('crypto');

// CPU-bound work runs here, off the main event loop.
const hash = crypto.pbkdf2Sync(
  workerData.password, workerData.salt, 1_000_000, 64, 'sha512'
);
parentPort.postMessage(hash.toString('hex'));

// --- main server ---
const express = require('express');
const { Worker } = require('worker_threads');
const app = express();
app.use(express.json());

function hashInWorker(password, salt) {
  return new Promise((resolve, reject) => {
    const worker = new Worker('./hash-worker.js', {
      workerData: { password, salt },
    });
    worker.once('message', (result) => {
      resolve(result);
      worker.terminate();            // clean up this one-shot worker
    });
    worker.once('error', reject);    // worker threw
    worker.once('exit', (code) => {  // crashed before posting a message
      if (code !== 0) reject(new Error('Worker stopped, exit code ' + code));
    });
  });
}

app.post('/hash', async (req, res, next) => {
  try {
    // The await yields to the event loop; other requests are served while
    // the worker computes on its own thread.
    const hash = await hashInWorker(req.body.password, 'static-salt');
    res.json({ hash });
  } catch (err) {
    next(err);
  }
});

app.listen(3000);
